<section class="container section"><h1>Administrar usuarios</h1><div class="admin-layout"><div class="panel"><h2><?=$edit?'Editar usuario':'Nuevo usuario'?></h2><form method="post" action="index.php?route=admin/user/save"><input type="hidden" name="csrf_token" value="<?=Security::csrfToken()?>"><input type="hidden" name="id" value="<?=$edit['id']??0?>"><label>Nombre<input name="name" minlength="3" maxlength="100" value="<?=Security::e($edit['name']??'')?>" required></label><label>Correo<input type="email" name="email" maxlength="150" value="<?=Security::e($edit['email']??'')?>" required></label><label>Teléfono<input name="phone" maxlength="20" value="<?=Security::e($edit['phone']??'')?>"></label><label>Rol<select name="role"><option value="client" <?=($edit['role']??'client')==='client'?'selected':''?>>Cliente</option><option value="admin" <?=($edit['role']??'')==='admin'?'selected':''?>>Administrador</option></select></label><label>Estado<select name="status"><option value="1" <?=($edit['status']??1)==1?'selected':''?>>Activo</option><option value="0" <?=isset($edit['status'])&&$edit['status']==0?'selected':''?>>Inactivo</option></select></label><label>Contraseña <?= $edit?'(dejar vacía para conservarla)':'' ?><input type="password" name="password" minlength="6" <?=$edit?'':'required'?>></label><button class="btn">Guardar usuario</button></form></div><div class="table-wrap"><table><thead><tr><th>Nombre</th><th>Correo</th><th>Rol</th><th>Estado</th><th>Fecha</th><th>Acciones</th></tr></thead><tbody><?php foreach($users as $u):?><tr><td><?=Security::e($u['name'])?></td><td><?=Security::e($u['email'])?></td><td><?=Security::e($u['role'])?></td><td><?=$u['status']?'Activo':'Inactivo'?></td><td><?=$u['created_at']?></td><td><a href="index.php?route=admin/users&id=<?=$u['id']?>">Editar</a><form class="inline" method="post" action="index.php?route=admin/user/delete" onsubmit="return confirm('¿Eliminar usuario?')"><input type="hidden" name="csrf_token" value="<?=Security::csrfToken()?>"><input type="hidden" name="id" value="<?=$u['id']?>"><button class="link danger">Eliminar</button></form></td></tr><?php endforeach;?></tbody></table></div></div></section>
